window.HK_LC10 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["A kayak has been left on a beach.", "The man is getting out of a boat.", "A swimmer has jumped into a river.", "The man is holding on to some paddles."], "optko": ["카약이 해변에 남겨져 있다.", "남자가 배에서 나오고 있다.", "수영하는 사람이 강으로 뛰어들었다.", "남자는 노를 붙잡고 있다."], "ans": 3, "audio": "Test10_01.mp3", "img": "hk_t10_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["Some people are checking information on a screen.", "Some people are waiting in a line.", "Some people are typing on keyboards.", "Some people are filling out forms."], "optko": ["몇몇 사람들이 화면의 정보를 확인하고 있다.", "몇몇 사람들이 줄을 서서 기다리고 있다.", "몇몇 사람들이 키보드로 타이핑하고 있다.", "몇몇 사람들이 양식을 기입하고 있다."], "ans": 1, "audio": "Test10_02.mp3", "img": "hk_t10_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["Some water is spraying into the air.", "A group is biking down the street.", "A tourist is taking a photograph.", "A man is looking at a map."], "optko": ["물이 공기 중으로 뿌려지고 있다.", "한 무리가 자전거를 타고 길을 내려가고 있다.", "한 관광객이 사진을 찍고 있다.", "한 남자가 지도를 보고 있다."], "ans": 0, "audio": "Test10_03.mp3", "img": "hk_t10_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["He's holding up a machine's lid.", "He's stacking some binders.", "He's filing documents in an office.", "He's getting up from a stool."], "optko": ["그는 기계의 덮개를 잡고 있다.", "그는 바인더를 쌓고 있다.", "그는 사무실에서 서류를 정리하고 있다.", "그는 의자에서 일어나고 있다."], "ans": 0, "audio": "Test10_04.mp3", "img": "hk_t10_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["Spectators are exiting a theater.", "A staircase is positioned below a seating area.", "Some people are performing on a stage.", "Audience members are clapping their hands."], "optko": ["관중들이 극장에서 나가고 있다.", "계단이 좌석 밑에 위치해 있다.", "몇몇 사람들이 무대 위에서 공연을 하고 있다.", "청중들이 박수를 치고 있다."], "ans": 2, "audio": "Test10_05.mp3", "img": "hk_t10_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["Some lines are being painted on asphalt.", "A ship is sailing under a bridge.", "Some vehicles are parked in a row.", "A road has been blocked off to pedestrians."], "optko": ["아스팔트 위에 선들이 그려지고 있다.", "배가 다리 밑을 항해하고 있다.", "자동차들이 나란히 주차되어 있다.", "도로가 보행자들에게 차단되었다."], "ans": 2, "audio": "Test10_06.mp3", "img": "hk_t10_q6.jpg"}, {"n": 7, "part": 2, "q": "Who's responsible for restocking this merchandise?", "qko": "이 상품을 다시 채우는 것을 누가 책임지고 있나요?", "opts": ["I really like that store.", "They're out of stock.", "I know I'm not."], "optko": ["저는 그 상점을 정말 좋아해요.", "그것들은 품절이에요.", "제가 아니라는 건 알아요."], "ans": 2, "audio": "Test10_07.mp3"}, {"n": 8, "part": 2, "q": "When should we meet at the bus station?", "qko": "버스 정류장에서 언제 만날까요?", "opts": ["For the bus driver.", "Anytime after 1:30 P.M.", "Yes, I can meet then."], "optko": ["버스 기사를 위해서요.", "오후 1시 30분 이후에는 언제든지요.", "네, 그때 만날 수 있어요."], "ans": 1, "audio": "Test10_08.mp3"}, {"n": 9, "part": 2, "q": "How much more equipment do we need to order?", "qko": "우리는 장비를 얼마나 더 주문해야 하나요?", "opts": ["We have enough machines.", "The order number.", "It's equipped with a sensor."], "optko": ["우리는 충분한 기계들이 있어요.", "주문 번호요.", "이것은 센서를 갖추고 있어요."], "ans": 0, "audio": "Test10_09.mp3"}, {"n": 10, "part": 2, "q": "The sales meeting won't last all morning, will it?", "qko": "영업 회의는 오전 내내 계속되지는 않을 거예요, 그렇죠?", "opts": ["Mostly online revenue.", "No, just 30 minutes.", "It's 10 feet long."], "optko": ["주로 온라인 수익이요.", "아니요, 단지 30분이요.", "이건 길이가 10피트예요."], "ans": 1, "audio": "Test10_10.mp3"}, {"n": 11, "part": 2, "q": "Ms. Gordon left her purse on my desk.", "qko": "Ms. Gordon이 그녀의 지갑을 제 책상 위에 놓고 갔어요.", "opts": ["I'll let her know.", "The bag is discounted right now.", "Head left at the intersection."], "optko": ["제가 그녀에게 알려줄게요.", "이 가방은 지금 바로 할인 중이에요.", "교차로에서 왼쪽으로 가세요."], "ans": 0, "audio": "Test10_11.mp3"}, {"n": 12, "part": 2, "q": "Have you been to Benson Stadium since it was expanded?", "qko": "Benson 경기장이 확장된 이후로 그곳에 가본 적이 있나요?", "opts": ["I've known them since college.", "Tickets for a game.", "Yes, just last weekend."], "optko": ["저는 그들을 대학 때부터 알고 있어요.", "경기 티켓들이요.", "네, 바로 지난주에요."], "ans": 2, "audio": "Test10_12.mp3"}, {"n": 13, "part": 2, "q": "You should leave now for your appointment.", "qko": "약속에 가기 위해 당신은 지금 떠나야 해요.", "opts": ["It was with a few clients.", "The flight left on time.", "Yes, there could be heavy traffic."], "optko": ["몇 명의 고객들과 함께였어요.", "비행기는 제때 떠났어요.", "네, 교통 체증이 있을 수도 있겠어요."], "ans": 2, "audio": "Test10_13.mp3"}, {"n": 14, "part": 2, "q": "Which photo should we use for the magazine's cover?", "qko": "우리는 잡지의 표지에 어떤 사진을 사용해야 할까요?", "opts": ["I can take photos of those.", "The one on the left is the best.", "The publication is quite popular."], "optko": ["제가 그것들의 사진을 찍을 수 있어요.", "왼쪽 것이 가장 좋네요.", "그 간행물은 꽤 인기가 있어요."], "ans": 1, "audio": "Test10_14.mp3"}, {"n": 15, "part": 2, "q": "How many of us are going to Sheldon's birthday party?", "qko": "Sheldon의 생일 파티에 우리 중 몇 명이 가나요?", "opts": ["Deloris can't come, so just 10.", "It's only partly painted.", "Most of the billing statements."], "optko": ["Deloris가 올 수 없어서 단 10명이요.", "이건 부분적으로만 색칠됐어요.", "대부분의 요금 청구서요."], "ans": 0, "audio": "Test10_15.mp3"}, {"n": 16, "part": 2, "q": "Where was the pack of printer paper set?", "qko": "프린터 용지 묶음은 어디에 있었나요?", "opts": ["For a copy machine.", "Cindy should know.", "Yes, I'll get it."], "optko": ["복사기용이요.", "Cindy가 알 거예요.", "네, 제가 그걸 가져올게요."], "ans": 1, "audio": "Test10_16.mp3"}, {"n": 17, "part": 2, "q": "Has the finance team responded to your reimbursement request?", "qko": "재무팀이 당신의 변제 요청에 답변을 했나요?", "opts": ["No, nobody has contacted me yet.", "That's his department.", "To my checking account."], "optko": ["아니요, 아직 아무도 제게 연락하지 않았어요.", "이건 그의 부서예요.", "제 당좌 예금 계좌로요."], "ans": 0, "audio": "Test10_17.mp3"}, {"n": 18, "part": 2, "q": "Do you know why the road is blocked?", "qko": "당신은 왜 길이 막혀 있는지 아시나요?", "opts": ["For a few days, I think.", "On Yale Street.", "There was a bad accident."], "optko": ["며칠 동안인 것 같아요.", "Yale가에요.", "심각한 사고가 있었어요."], "ans": 2, "audio": "Test10_18.mp3"}, {"n": 19, "part": 2, "q": "How did the medical convention go?", "qko": "의학 컨벤션은 어땠나요?", "opts": ["Actually, I didn't participate in it.", "Conference Room 1 is available.", "I have a medical degree."], "optko": ["사실, 저는 거기에 참석하지 않았어요.", "제1 회의실을 사용할 수 있어요.", "저는 의학 학위를 갖고 있어요."], "ans": 0, "audio": "Test10_19.mp3"}, {"n": 20, "part": 2, "q": "Please tell the shipping clerk that the package must arrive by noon on Wednesday.", "qko": "운송 담당 직원에게 소포가 수요일 정오까지는 도착해야 한다고 말해주세요.", "opts": ["Overnight delivery rates.", "OK, I will.", "I got there on Friday."], "optko": ["익일 배송 요금이요.", "네, 그럴게요.", "저는 금요일에 거기 도착했어요."], "ans": 1, "audio": "Test10_20.mp3"}, {"n": 21, "part": 2, "q": "When is the play Lost in Time running?", "qko": "연극 Lost in Time이 언제 상연하나요?", "opts": ["A brief intermission.", "For another week.", "In about an hour."], "optko": ["짧은 휴식 시간이요.", "일주일간 더요.", "약 한 시간 뒤에요."], "ans": 2, "audio": "Test10_21.mp3"}, {"n": 22, "part": 2, "q": "I'd like to renew my monthly subscription to Business Insight.", "qko": "저는 Business Insight지의 월정 구독을 갱신하고 싶어요.", "opts": ["A seminar during October.", "I'm happy to help with that.", "No, we have few subscribers."], "optko": ["10월 중의 세미나요.", "제가 기꺼이 그걸 도와드릴게요.", "아니요, 우리는 구독자들이 적어요."], "ans": 1, "audio": "Test10_22.mp3"}, {"n": 23, "part": 2, "q": "What concerns did instructors share with the administrator?", "qko": "강사들이 관리자와 어떤 문제들을 공유했나요?", "opts": ["Just follow the instructions.", "That's certainly concerning.", "Hasn't Mr. Porter already told you?"], "optko": ["그저 지침들을 따르세요.", "그건 확실히 걱정스럽네요.", "Mr. Porter가 이미 당신에게 말하지 않았나요?"], "ans": 2, "audio": "Test10_23.mp3"}, {"n": 24, "part": 2, "q": "Did the sellers accept our final offer on the house, or did they reject it?", "qko": "판매자들이 집에 대한 우리의 최종 제안을 수락했나요, 아니면 거절했나요?", "opts": ["We sold more properties last year.", "The open house was on Tuesday.", "Our agent said they agreed to it."], "optko": ["우리는 작년에 더 많은 건물들을 팔았어요.", "공개일은 화요일이었어요.", "우리 중개인이 그들이 그것에 동의했다고 말했어요."], "ans": 2, "audio": "Test10_24.mp3"}, {"n": 25, "part": 2, "q": "Why was I assigned to the Greenway Project?", "qko": "제가 왜 Greenway 프로젝트에 배정되었나요?", "opts": ["Because the door is locked.", "Mr. Dobson made that decision, not me.", "I'll consider your proposal."], "optko": ["문이 잠겼기 때문이에요.", "제가 아니라 Mr. Dobson이 그 결정을 내렸어요.", "당신의 제안을 고려해 볼게요."], "ans": 1, "audio": "Test10_25.mp3"}, {"n": 26, "part": 2, "q": "Can't we stop for coffee on the way to work?", "qko": "일하러 가는 길에 커피를 사러 잠깐 들를 수 없나요?", "opts": ["Thanks for the tea.", "If there's enough time.", "I'm fine with my current job."], "optko": ["차 감사합니다.", "만약 충분한 시간이 있으면요.", "저는 제 현재 직업이 좋아요."], "ans": 1, "audio": "Test10_26.mp3"}, {"n": 27, "part": 2, "q": "Which of the people who auditioned for the TV program do you like?", "qko": "당신은 텔레비전 프로그램의 오디션에 참가한 사람들 중 누구를 좋아하나요?", "opts": ["It was an action film.", "I really like the dessert.", "They all did outstandingly well."], "optko": ["그건 액션 영화였어요.", "저는 그 디저트가 정말 좋아요.", "그들은 모두 뛰어나게 잘했어요."], "ans": 2, "audio": "Test10_27.mp3"}, {"n": 28, "part": 2, "q": "Are you interested in seeing a musical performance with me next week?", "qko": "당신은 다음 주에 저와 음악 공연을 보는 것에 관심이 있나요?", "opts": ["No, we watched the tutorial instead.", "I never learned to play it.", "So long as I'm available then."], "optko": ["아니요, 우리는 대신 사용 지침 프로그램을 봤어요.", "저는 그걸 연주하는 걸 배운 적이 없어요.", "제가 그때 시간이 되기만 하면요."], "ans": 2, "audio": "Test10_28.mp3"}, {"n": 29, "part": 2, "q": "Could you give me a hand editing this spreadsheet?", "qko": "이 스프레드시트를 수정하는 걸 도와주시겠어요?", "opts": ["Changes to our new logo.", "Just give me a moment.", "The handle is stuck."], "optko": ["우리 새로운 로고의 변경이요.", "제게 잠시만 시간을 주세요.", "핸들이 움직이지 않아요."], "ans": 1, "audio": "Test10_29.mp3"}, {"n": 30, "part": 2, "q": "We're still planning to go to the technology trade show, right?", "qko": "우리는 여전히 기술 무역 박람회에 갈 계획이죠, 그렇죠?", "opts": ["We don't need the parts any longer.", "Let me check with Bailey on that.", "Yes, we're planning on buying a few."], "optko": ["우리는 그 부품들이 더 이상 필요 없어요.", "제가 그것에 대해 Bailey에게 확인해 볼게요.", "네, 우리는 약간을 구매할 계획이에요."], "ans": 1, "audio": "Test10_30.mp3"}, {"n": 31, "part": 2, "q": "May I please talk to Mr. Himura from the marketing division?", "qko": "마케팅 부서의 Mr. Himura와 이야기할 수 있을까요?", "opts": ["The talk was quite short.", "No, it was for a promotional campaign.", "Please hold while I transfer your call."], "optko": ["대화는 꽤 짧았어요.", "아니요, 그건 홍보 캠페인을 위한 것이었어요.", "당신의 전화를 돌려드리는 동안 기다려주세요."], "ans": 2, "audio": "Test10_31.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Br", "audio": "Test10_32-34.mp3", "qs": [{"n": 32, "q": "Why will the man travel to Beijing?", "opts": ["To meet with a client", "To attend a seminar", "To inspect a factory", "To do some sightseeing"], "ans": 1, "ko": "남자는 왜 베이징에 갈 것인가?"}, {"n": 33, "q": "What does the man suggest?", "opts": ["Making a phone call", "Filling out a form", "Looking up a venue", "Visiting a Web site"], "ans": 0, "ko": "남자는 무엇을 제안하는가?"}, {"n": 34, "q": "What does the woman say about Eli Price?", "opts": ["He did not read a publication.", "He recently released a book.", "He will edit a presentation.", "He cannot join a gathering."], "ans": 1, "ko": "여자는 Eli Price에 관해 무엇을 말하는가?"}], "script": [{"sp": "M", "en": "Hey, Pauline. Have you registered for the engineering seminar in Beijing yet? I've just booked my flight there.", "ko": "안녕하세요, Pauline. 베이징에서 열리는 공학 기술 세미나에 등록하셨어요? 저는 방금 거기로 가는 비행편을 예약했어요."}, {"sp": "W", "en": "Not yet. I tried yesterday, but the event's Web site wasn't working.", "ko": "아직이요. 어제 하려고 했는데, 그 행사의 웹사이트가 작동하지 않았어요."}, {"sp": "M", "en": "Then you should probably just do it over the phone since registration ends today.", "ko": "등록이 오늘 끝나기 때문에 그럼 당신은 전화로 해야 할 것 같네요."}, {"sp": "W", "en": "Good idea. I definitely don't want to miss out on the event.", "ko": "좋은 생각이에요. 저는 그 행사를 절대 놓치고 싶지 않아요."}, {"sp": "M", "en": "Definitely not. I heard the famous engineer Eli Price will be a guest speaker. He actually developed the machines we use in our factory.", "ko": "물론 안 되죠. 유명한 기술자인 Eli Price가 초청 연사일 거라고 들었어요. 사실 우리가 공장에서 사용하는 기계들을 그가 개발했잖아요."}, {"sp": "W", "en": "I know. I'm reading the book he published last month. He has some interesting ideas about robotics.", "ko": "저도 알아요. 저는 그가 지난달에 출간한 책을 읽고 있어요. 그는 로봇 공학에 대해 흥미로운 견해를 갖고 있어요."}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Au", "audio": "Test10_35-37.mp3", "qs": [{"n": 35, "q": "What type of business do the speakers probably work for?", "opts": ["An accounting firm", "A marketing company", "A clothing manufacturer", "A department store"], "ans": 2, "ko": "화자들은 어떤 종류의 업체에서 일하는 것 같은가?"}, {"n": 36, "q": "According to the man, what did Nancy recently do?", "opts": ["Completed an analysis", "Gave a demonstration", "Designed more apparel", "Contacted a representative"], "ans": 0, "ko": "남자에 따르면, Nancy는 최근에 무엇을 했는가?"}, {"n": 37, "q": "What does the man say about the training session?", "opts": ["It will take place tomorrow.", "It will focus on a computer program.", "It will be recorded by a film crew.", "It will be moved to another room."], "ans": 1, "ko": "남자는 교육에 관해 무엇을 말하는가?"}], "script": [{"sp": "W", "en": "Sales of our dresses and pants have dropped by 5 percent since we started selling them through the Hadley Outlet.", "ko": "우리가 Hadley 아웃렛을 통해 우리의 원피스와 바지를 팔기 시작한 이후로, 그것들의 매출이 5퍼센트 떨어졌어요."}, {"sp": "M", "en": "Yes, Nancy told me about that after she finished analyzing last quarter's financial figures. That's a big problem, isn't it?", "ko": "네, Nancy가 지난 분기의 재정 수치를 분석하는 걸 마치고 나서 그것에 대해 제게 말해줬어요. 그건 정말 큰 문제예요, 그렇지 않나요?"}, {"sp": "W", "en": "Absolutely. Accordingly, I've arranged an appointment with one of Hadley Outlet's representatives so we can brainstorm ways to boost revenues. We'll be getting together next Wednesday at 3 P.M., if you want to join us.", "ko": "물론이죠. 그런 이유로 우리가 수익을 증진시킬 방안을 떠올릴 수 있도록 Hadley 아웃렛의 대표들 중 한 명과 약속을 잡아 놓았어요. 당신도 함께 하길 원한다면, 저희는 다음 주 수요일 오후 3시에 모일 예정이에요."}, {"sp": "M", "en": "I wish I could, but I'm scheduled to train our interns on the accounting software that afternoon. Please e-mail me the notes from the meeting, though. I'd like to review what you discuss.", "ko": "저도 그럴 수 있다면 좋을 텐데, 그날 오후에 회계 소프트웨어에 대해 인턴들을 교육할 예정이에요. 하지만 회의에서 나온 메모들을 저에게 이메일로 보내 주세요. 당신이 논의하는 것을 확인해 보고 싶어요."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Br", "audio": "Test10_38-40.mp3", "qs": [{"n": 38, "q": "What are the speakers mainly discussing?", "opts": ["A customer complaint", "A product description", "A company policy", "A utility bill"], "ans": 2, "ko": "화자들은 주로 무엇에 관해 이야기하고 있는가?"}, {"n": 39, "q": "What problem does the woman mention?", "opts": ["A memo was accidentally deleted.", "A business card is missing.", "A dentist is unavailable.", "A device was left at home."], "ans": 3, "ko": "여자는 무슨 문제를 언급하는가?"}, {"n": 40, "q": "Why does the man say, \"It's a quick call\"?", "opts": ["To agree to a request", "To apologize for a disruption", "To ask a colleague to wait", "To ease a concern"], "ans": 3, "ko": "남자는 왜 \"짧은 통화잖아요\"라고 말하는가?"}], "script": [{"sp": "M", "en": "Kendra, did you see the memo our supervisor sent this morning about not using our company cell phones for personal calls?", "ko": "Kendra, 우리 관리자가 개인적인 통화에 회사 휴대 전화를 사용하지 않는 것에 대해서 오늘 아침에 보낸 회람을 봤나요?"}, {"sp": "W", "en": "I did . . . But, um, I'm worried because I forgot my phone at my apartment today, and I need to contact someone.", "ko": "봤어요… 하지만, 음, 저는 오늘 아파트에 제 휴대 전화를 놓고 왔는데, 누군가에게 연락을 해야 해서 걱정이네요."}, {"sp": "M", "en": "Who are you planning to call today?", "ko": "오늘 누구에게 전화할 계획인가요?"}, {"sp": "W", "en": "I need to cancel an appointment with my dentist. I'm going to have to use my company phone to do this . . . I don't want to get in trouble, though.", "ko": "저는 치과 진료 예약을 취소해야 해요. 이걸 하기 위해 회사 휴대 전화를 사용해야 할 것 같아요… 하지만, 곤란에 처하고 싶지는 않네요."}, {"sp": "M", "en": "It's a quick call. I don't think it will be an issue.", "ko": "짧은 통화잖아요. 저는 문제가 되지 않을 거라고 생각해요."}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Am", "audio": "Test10_41-43.mp3", "qs": [{"n": 41, "q": "What type of business does the man probably work for?", "opts": ["A moving company", "A furniture retailer", "An insurance provider", "A construction firm"], "ans": 0, "ko": "남자는 어떤 종류의 업체에서 일하는 것 같은가?"}, {"n": 42, "q": "What does the woman tell the man to do?", "opts": ["Read an agreement", "Park a truck in a garage", "Place items on the floor", "Call a worker for help"], "ans": 2, "ko": "여자는 남자에게 무엇을 하라고 말하는가?"}, {"n": 43, "q": "What does the man say about the invoice?", "opts": ["It can be sent electronically.", "It has been received already.", "It is enclosed in a box.", "It contains an error."], "ans": 0, "ko": "남자는 청구서에 관해 무엇을 말하는가?"}], "script": [{"sp": "M", "en": "Ms. Kearney, we're almost done bringing your belongings into your new home. Ah . . . but where should I place these boxes marked as decorations?", "ko": "Ms. Kearney, 저희는 새 집으로 당신의 물건들을 가져오는 것을 거의 다 마쳤습니다. 아… 그런데 장식품이라고 표시된 이 상자들을 어디에 놓으면 될까요?"}, {"sp": "W", "en": "Oh, those are the ornaments for my living room. Please put them on the floor by the brown cabinet.", "ko": "아, 그건 제 거실을 위한 장식품이에요. 갈색 장식장 옆의 바닥에 놓아 주세요."}, {"sp": "M", "en": "All right. That's everything, then. Would you like our company to e-mail you the invoice, or would it be better to mail you a paper copy?", "ko": "알겠습니다. 그럼 이게 전부네요. 저희 회사에서 당신에게 청구서를 이메일로 보내드리길 원하시나요, 아니면 서류 사본을 보내드리는 것이 더 나을까요?"}, {"sp": "W", "en": "An e-mail would be great, thanks. You should have my contact information on record. Do you happen to know how much my bill will be?", "ko": "이메일이 좋겠네요, 감사합니다. 제 연락처가 기록에 있을 거예요. 혹시 제 청구서가 얼마일지 아시나요?"}, {"sp": "M", "en": "Yes. You'll be charged a flat rate of $350.", "ko": "네. 350달러의 고정 요금이 청구될 거예요."}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "speakers": "W1-Am / M-Ca / W2-Br", "audio": "Test10_44-46.mp3", "qs": [{"n": 44, "q": "What is the conversation mainly about?", "opts": ["An office opening", "A marketing campaign", "An interview process", "A business trip"], "ans": 0, "ko": "대화는 주로 무엇에 관한 것인가?"}, {"n": 45, "q": "What does the man inquire about?", "opts": ["A project deadline", "A building address", "A meeting location", "A facility supervisor"], "ans": 3, "ko": "남자는 무엇에 관해 문의하는가?"}, {"n": 46, "q": "What does the man suggest that Kara do?", "opts": ["Make an announcement", "Apply for a position", "Speak to an executive", "Review a résumé"], "ans": 1, "ko": "남자는 Kara에게 무엇을 하라고 제안하는가?"}], "script": [{"sp": "W1", "en": "Everyone, we're planning to open another branch of our public relations company in Tacoma.", "ko": "여러분, 타코마에 우리의 홍보 회사가 다른 지사를 열 계획이에요."}, {"sp": "M", "en": "Wow . . . That decision was made quickly! I thought the CEO wouldn't approve that until next year.", "ko": "우아… 그 결정이 빨리 이루어졌네요! 저는 최고 경영자가 내년이 되어서야 그걸 승인할 거라고 생각했어요."}, {"sp": "W2", "en": "Me too. It makes sense, though. Many companies are located there, so it's a promising market for us.", "ko": "저도요. 하지만 이해가 되네요. 많은 회사들이 거기에 위치해 있어서 우리에게 유망한 시장이잖아요."}, {"sp": "M", "en": "Right. Um . . . Kara, do you know who will manage the new branch?", "ko": "맞아요. 음… Kara, 새 지사를 누가 관리할지 알고 있나요?"}, {"sp": "W1", "en": "No, but the executive team will discuss that in next Thursday's meeting. I heard they are planning to consider both internal and external candidates.", "ko": "아니요, 하지만 경영진이 다음 주 목요일 회의에서 그것을 논의할 거예요. 저는 그들이 내부와 외부 후보를 모두 고려할 계획이라고 들었어요."}, {"sp": "M", "en": "Well, you should submit an application. You'd be a perfect fit.", "ko": "음, 당신은 지원서를 제출해야 해요. 당신이 딱 맞을 거예요."}, {"sp": "W1", "en": "Thanks. I might give it a try.", "ko": "고마워요. 한번 해봐야겠어요."}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "speakers": "M-Ca / W-Am", "audio": "Test10_47-49.mp3", "qs": [{"n": 47, "q": "What is the man's problem?", "opts": ["An appliance is not available.", "A record is inaccurate.", "A shipment has not arrived.", "A product has malfunctioned."], "ans": 3, "ko": "남자의 문제는 무엇인가?"}, {"n": 48, "q": "Why does the man say, \"I purchased a Gateway 350\"?", "opts": ["To check a price", "To request a form", "To make a correction", "To change an order"], "ans": 2, "ko": "남자는 왜 \"저는 Gateway 350을 구입했어요\"라고 말하는가?"}, {"n": 49, "q": "What does the woman say she can do?", "opts": ["Pick up an item", "Process a refund", "Make an appointment", "Expedite a delivery"], "ans": 2, "ko": "여자는 그녀가 무엇을 할 수 있다고 말하는가?"}], "script": [{"sp": "M", "en": "My name is Tim Jones, and I'm calling to report a defective appliance. My order number is 44312.", "ko": "제 이름은 Tim Jones이고, 결함이 있는 기기를 알리기 위해 전화드렸어요. 제 주문 번호는 44312예요."}, {"sp": "W", "en": "Just a minute, Mr. Jones . . . OK, our records show that you ordered a Steelman 90B stove. Is that correct?", "ko": "잠시만요, Mr. Jones… 네, 저희 기록은 고객님께서 Steelman 90B 난로를 주문하셨다고 보여주네요. 이것이 맞나요?"}, {"sp": "M", "en": "I purchased a Gateway 350. Again, the order number is 44312.", "ko": "저는 Gateway 350을 구입했어요. 다시 말씀드리면, 제 주문 번호는 44312예요."}, {"sp": "W", "en": "Oh, I misheard the last digit. My apologies. Yes, I see your purchase information now. What exactly is the problem?", "ko": "아, 제가 마지막 숫자를 잘못 들었네요. 죄송합니다. 네, 이제 고객님의 구매 정보가 보입니다. 정확히 무엇이 문제인가요?"}, {"sp": "M", "en": "I'm not sure. When I press the power button, nothing happens.", "ko": "저도 잘 모르겠어요. 제가 전원 버튼을 누르면, 아무 일도 일어나지 않아요."}, {"sp": "W", "en": "I see. Would you like me to arrange a time for a repairperson to visit your home?", "ko": "알겠습니다. 수리공이 고객님 댁에 방문하도록 제가 시간을 정해 드릴까요?"}, {"sp": "M", "en": "Yes, please. Any time before noon on Friday would be convenient for me.", "ko": "네, 부탁드려요. 금요일 낮 12시 전에는 언제든 괜찮아요."}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Br", "audio": "Test10_50-52.mp3", "qs": [{"n": 50, "q": "Why is the man calling?", "opts": ["To book a trip", "To purchase a publication", "To learn about a product", "To request a meeting"], "ans": 3, "ko": "남자는 왜 전화를 하는가?"}, {"n": 51, "q": "What does the woman have planned on Friday?", "opts": ["A business luncheon", "A press conference", "A book launch", "A personal trip"], "ans": 0, "ko": "여자는 금요일에 무엇을 하려고 계획하는가?"}, {"n": 52, "q": "What does the woman agree to do?", "opts": ["Subscribe to some magazines", "Participate in a photo shoot", "Donate some money", "Sign autographs for fans"], "ans": 1, "ko": "여자는 무엇을 하기로 동의하는가?"}], "script": [{"sp": "M", "en": "Hello, Ms. Beale. This is Dan Feingold from BizLife Magazine. Do you have any interest in being interviewed for our publication? We'd like to write a piece on your recently published book on management strategies.", "ko": "안녕하세요, Ms. Beale. 저는 BizLife지의 Dan Feingold입니다. 혹시 저희 간행물에 실리는 인터뷰에 응하시는 데에 관심이 있으신가요? 경영 전략에 관해 최근에 출간된 당신의 책에 대해 기사를 쓰고 싶습니다."}, {"sp": "W", "en": "Absolutely. I'm a big fan of your magazine!", "ko": "당연하죠. 저는 당신 잡지의 열혈 팬이에요!"}, {"sp": "M", "en": "That's wonderful to hear. Would you be able to come to our office in downtown Portland on Friday afternoon for the interview?", "ko": "그거 정말 반갑네요. 인터뷰를 위해 금요일 오후에 포틀랜드 시내에 있는 저희 사무실로 와주실 수 있나요?"}, {"sp": "W", "en": "Actually, I'm having lunch with my company's CEO that day. Saturday is more convenient for me.", "ko": "사실, 그날 저는 저희 회사의 최고 경영자와 점심 약속이 있어요. 토요일이 제게 더 편해요."}, {"sp": "M", "en": "We can manage that. Oh, and are you willing to pose for some pictures? We want to print them next to the article.", "ko": "그렇게 할 수 있을 것 같아요. 아, 그리고 사진 촬영을 위해 포즈를 취해주실 수 있을까요? 저희는 사진들을 기사 옆에 게재하고자 해요."}, {"sp": "W", "en": "Of course.", "ko": "물론이죠."}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Cn", "audio": "Test10_53-55.mp3", "qs": [{"n": 53, "q": "What is the conversation mainly about?", "opts": ["A service request", "A sports competition", "A uniform design", "A community center"], "ans": 0, "ko": "대화는 주로 무엇에 관한 것인가?"}, {"n": 54, "q": "According to the woman, what should people be able to do on a Web site?", "opts": ["Watch some videos", "Order a uniform", "Reserve tickets", "Register for a workshop"], "ans": 2, "ko": "여자에 따르면, 사람들은 웹사이트에서 무엇을 할 수 있어야 하는가?"}, {"n": 55, "q": "What will happen next?", "opts": ["A photo will be taken.", "A presentation will be given.", "A proposal will be reviewed.", "An estimate will be provided."], "ans": 3, "ko": "다음에 무슨 일이 일어날 것인가?"}], "script": [{"sp": "W", "en": "Good morning. My name is Maureen Price. I came to your office a week ago to discuss a Web site you said you could design for the new amateur baseball team that I manage.", "ko": "안녕하세요. 제 이름은 Maureen Price입니다. 저는 제가 관리하는 새 아마추어 야구팀을 위해 당신이 만들 수 있다고 말했던 웹사이트에 관해 논의하기 위해 일주일 전에 당신의 사무실에 왔었어요."}, {"sp": "M", "en": "Oh, right. Have you decided which features you'd like to include?", "ko": "아, 맞아요. 포함하고 싶은 특징들을 결정하셨나요?"}, {"sp": "W", "en": "Yes. I'll need a page where people can reserve tickets. There should be a schedule of games, too.", "ko": "네. 저는 사람들이 티켓을 예약할 수 있는 페이지가 필요할 것 같아요. 그리고 거기에는 경기 일정도 있어야 해요."}, {"sp": "M", "en": "Do you want any video content to be featured as well? We only charge an extra $100 to do so.", "ko": "동영상 콘텐츠도 포함하기를 원하시나요? 저희는 그렇게 하는 데 추가로 단지 100달러만 받습니다."}, {"sp": "W", "en": "We intend to put up players' photos—but not any videos.", "ko": "저희는 선수들의 사진을 게시하려고 생각하지만 동영상은 아니에요."}, {"sp": "M", "en": "OK. Please take a seat, and I'll get a quote ready for you. It should only take a few minutes.", "ko": "알겠습니다. 여기에 앉아 계시면, 제가 견적을 준비해올게요. 단지 몇 분 정도 걸릴 겁니다."}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Cn", "audio": "Test10_56-58.mp3", "qs": [{"n": 56, "q": "Where must some crates be taken?", "opts": ["To a production plant", "To a loading dock", "To a storage building", "To a store showroom"], "ans": 2, "ko": "상자들을 어디로 가져가야 하는가?"}, {"n": 57, "q": "What problem does the man mention?", "opts": ["A vehicle is unavailable.", "A container has been misplaced.", "A building door is locked.", "A worker is late for a shift."], "ans": 0, "ko": "남자는 어떤 문제를 언급하는가?"}, {"n": 58, "q": "What does the man ask the woman to do?", "opts": ["Unpack a shipment", "Examine some labels", "Check a staff schedule", "Hold a team meeting"], "ans": 1, "ko": "남자는 여자에게 무엇을 해달라고 요청하는가?"}], "script": [{"sp": "W", "en": "These crates are too heavy, Mike. We can't move them from this loading dock to the warehouse without using the truck.", "ko": "이 상자들은 너무 무거워요, Mike. 우리는 트럭을 사용하지 않고 여기 짐 싣는 곳에서 창고까지 이것들을 옮길 수 없어요."}, {"sp": "M", "en": "But Kevin is using the truck right now. And we need to move this shipment before lunchtime.", "ko": "하지만 Kevin이 지금 트럭을 사용하고 있어요. 그리고 우리는 점심 시간 전에 이 배송품을 옮겨야 하고요."}, {"sp": "W", "en": "Kevin told me earlier today that he'd be back by 11 A.M. So . . . uh . . . he should be here any minute now.", "ko": "Kevin이 오전 11시까지 돌아올 거라고 오늘 일찍 제게 말했어요. 그러니까… 아… 그는 곧 여기에 올 거예요."}, {"sp": "M", "en": "Oh, OK. In that case, I'll wait for him. In the meantime, could you please double-check that the crates are labeled properly? We've had issues with that in the past.", "ko": "아, 알겠어요. 그렇다면 제가 그를 기다릴게요. 그동안에, 상자들에 제대로 상표가 붙었는지 다시 한번 확인해 주시겠어요? 우리는 이전에 그것과 관련해서 문제가 있었거든요."}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "speakers": "M-Cn / W1-Am / W2-Br", "audio": "Test10_59-61.mp3", "qs": [{"n": 59, "q": "What is mentioned about the ski resort?", "opts": ["It is attracting too few customers.", "It will be temporarily closed down.", "It hosted a competition.", "It will open a new restaurant."], "ans": 0, "ko": "스키 리조트에 관해 무엇이 언급되는가?"}, {"n": 60, "q": "What does Connie suggest?", "opts": ["Setting up a display", "Decreasing some rates", "Hiring more staff", "Meeting with a competitor"], "ans": 1, "ko": "Connie는 무엇을 제안하는가?"}, {"n": 61, "q": "What will the man do this afternoon?", "opts": ["Inspect a building site", "Sign some forms", "Share some ideas", "Clean up an area"], "ans": 2, "ko": "남자는 오늘 오후에 무엇을 할 것인가?"}], "script": [{"sp": "M", "en": "Unfortunately, our ski resort has had low occupancy numbers over the last few months. Could you two propose some ways to attract more visitors?", "ko": "안타깝게도, 저희 스키 리조트가 지난 몇 달 동안 낮은 점유율 수치를 기록해왔습니다. 더 많은 방문객을 끌어모을 수 있는 방법을 두 분께서 제안해 주시겠어요?"}, {"sp": "W1", "en": "How about building a new spa?", "ko": "새로운 온천을 짓는 것은 어떨까요?"}, {"sp": "M", "en": "That's a nice thought, but we can't afford to build any new structures.", "ko": "좋은 생각이지만, 우리는 새로운 건물을 지을 여유가 없어요."}, {"sp": "W2", "en": "Then why don't we create a sledding course? Guests could go up the mountain using our cable car and then sled down.", "ko": "그럼 썰매 코스를 만드는 건 어떨까요? 손님들은 우리 케이블카를 이용해 산 위로 올라가서 썰매를 타고 내려올 수 있을 거예요."}, {"sp": "M", "en": "I like that. Our biggest competitor has something similar. Anything to add, Connie?", "ko": "좋네요. 우리의 가장 큰 경쟁사가 비슷한 것을 갖고 있잖아요. 덧붙이실 게 있나요, Connie?"}, {"sp": "W1", "en": "Yes. I know several guests have mentioned that room rates are rather high. How about offering discounted prices as a promotion?", "ko": "네. 저는 몇몇 손님들이 객실 요금이 상당히 비싸다고 언급했다고 알고 있어요. 홍보 수단으로 할인된 가격을 제공하는 건 어떨까요?"}, {"sp": "M", "en": "Excellent suggestions. I'll mention both ideas at the executive meeting this afternoon.", "ko": "정말 좋은 제안들이에요. 제가 오늘 오후에 간부 회의에서 두 의견에 대해 말해 볼게요."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "speakers": "W-Br / M-Cn", "audio": "Test10_62-64.mp3", "qs": [{"n": 62, "q": "What is the woman working on?", "opts": ["Room decorations", "Event invitations", "Menu changes", "Seating arrangements"], "ans": 3, "ko": "여자는 무엇에 노력을 들이고 있는가?"}, {"n": 63, "q": "Look at the graphic. Who sent an e-mail half an hour ago?", "opts": ["Chau Nguyen", "Kayla Baker", "Javier Valencia", "Andre Wood"], "ans": 0, "ko": "시각 자료를 보시오. 누가 30분 전에 이메일을 보냈는가?"}, {"n": 64, "q": "According to the man, what happened last month?", "opts": ["Venue reservations were modified.", "Catering choices were confirmed.", "A conference center was renovated.", "A guest list was posted online."], "ans": 1, "ko": "남자에 따르면, 지난달에 무슨 일이 일어났는가?"}], "script": [{"sp": "W", "en": "Tom, I want to let you know that I'm almost finished with the seating chart for Friday's banquet. I'm trying to seat all the winners near the front of the venue.", "ko": "Tom, 저는 금요일 연회의 좌석 배치도를 거의 끝냈다는 걸 알려드리고 싶어요. 모든 수상자들을 장소의 앞쪽에 앉히려고 해요."}, {"sp": "M", "en": "Yes, they should have easy access to the stage. And that reminds me. We got an e-mail from the caterer for the event about 30 minutes ago. Have you read it yet?", "ko": "네, 그들은 무대에 쉽게 접근할 수 있어야 해요. 그러고 보니 생각나네요. 우리는 약 30분 전에 행사의 출장 연회 업체로부터 이메일을 받았어요. 벌써 읽으셨나요?"}, {"sp": "W", "en": "No. I've been focused on getting this chart finished. Beeman Corporation expanded its guest list this morning. Did the e-mail indicate that there will be some problems?", "ko": "아니요. 저는 이 배치도를 마무리하는 데에 집중하고 있었어요. Beeman 기업이 오늘 아침에 그들의 초청자 명단을 확대했거든요. 그 이메일이 무슨 문제가 있을 거라고 명시했나요?"}, {"sp": "M", "en": "Everything's fine as we decided on the menu a month ago. The message just mentioned the number of vegetarian meals that will be provided.", "ko": "우리가 메뉴를 한 달 전에 결정했기 때문에 모든 것이 괜찮아요. 메시지는 단지 제공될 채식주의자용 식사의 수를 언급했어요."}], "gimg": "hk_t10_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "speakers": "M/W", "audio": "Test10_65-67.mp3", "qs": [{"n": 65, "q": "What does the man ask about?", "opts": ["The price of a device", "The size of a printer", "The location of merchandise", "The duration of a promotion"], "ans": 2, "ko": "남자는 무엇에 관해 문의하는가?"}, {"n": 66, "q": "What does the woman say about the PaperPro 300?", "opts": ["It is a durable product.", "It is simple to use.", "It comes in several colors.", "It was featured in a magazine."], "ans": 1, "ko": "여자는 PaperPro 300에 관해 무엇을 말하는가?"}, {"n": 67, "q": "Look at the graphic. What discount will the man most likely receive?", "opts": ["5 percent off", "10 percent off", "15 percent off", "20 percent off"], "ans": 1, "ko": "시각 자료를 보시오. 남자는 얼마의 할인을 받을 것 같은가?"}], "script": [{"sp": "M", "en": "Excuse me. I need a printer for my home office. Where are they stocked?", "ko": "실례합니다. 저는 자택 사무실에 놓을 프린터가 필요해요. 그것들은 어디에 있나요?"}, {"sp": "W", "en": "Oh, they're right over here. Do you have a specific brand in mind?", "ko": "아, 바로 저기에 있어요. 마음에 두고 계신 구체적인 브랜드가 있으신가요?"}, {"sp": "M", "en": "Well, I had a PaperPro device before, and I really liked it. So, something from that brand would be excellent.", "ko": "음, 저는 이전에 PaperPro 기기를 갖고 있었는데, 정말 마음에 들었어요. 그래서 그 브랜드에서 나온 거라면 좋을 것 같아요."}, {"sp": "W", "en": "I'd recommend the PaperPro 300, then. Um . . . Our store received them from the manufacturer just last Monday. They're even more user-friendly than previous models.", "ko": "그렇다면 저는 PaperPro 300을 추천해요. 음… 저희 가게는 이것들을 그 제조사로부터 지난 월요일에 막 받았어요. 심지어 이전 모델들보다 더 사용하기 쉬워요."}, {"sp": "M", "en": "Perfect. I'll take one of those, please.", "ko": "완벽하네요. 그걸로 하나 할게요."}, {"sp": "W", "en": "Certainly. Also, do you need any paper for the printer? If so, here's a discount coupon for you to use. We're having a sale on those items today.", "ko": "물론이죠. 그리고, 프린터에 사용할 용지도 필요하신가요? 만약 그러시다면, 여기 사용할 수 있는 할인 쿠폰이 있어요. 저희가 오늘 이 제품들을 할인 판매하고 있거든요."}, {"sp": "M", "en": "I'll take two packs.", "ko": "두 묶음을 살게요."}], "gimg": "hk_t10_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "speakers": "M/W", "audio": "Test10_68-70.mp3", "qs": [{"n": 68, "q": "What did the man do earlier today?", "opts": ["Checked a bicycle tire", "Called a local repair shop", "Shopped for parts online", "Went for a bike ride"], "ans": 3, "ko": "남자는 오늘 일찍 무엇을 했는가?"}, {"n": 69, "q": "What problem does the woman mention?", "opts": ["A request will take some time to fulfill.", "A store does not sell a certain brand.", "A credit card has been rejected.", "A component was not properly installed."], "ans": 0, "ko": "여자는 무슨 문제를 언급하는가?"}, {"n": 70, "q": "Look at the graphic. How much will be deducted from the total cost?", "opts": ["$105", "$50", "$35", "$5"], "ans": 2, "ko": "시각 자료를 보시오. 총 가격에서 얼마가 공제될 것인가?"}], "script": [{"sp": "M", "en": "Good afternoon. I was biking this morning and noticed that my bicycle is making a lot of noise.", "ko": "안녕하세요. 저는 오늘 아침에 자전거를 타다가 제 자전거에서 소음이 많이 난다는 것을 알게 됐어요."}, {"sp": "W", "en": "Let me take a look . . . Hmm . . . Quite a few parts need to be updated.", "ko": "한번 볼게요… 흠… 상당 부분이 새 부품으로 교체되어야겠네요."}, {"sp": "M", "en": "I see. Would you be able to take care of that today?", "ko": "그렇군요. 오늘 그것을 처리해주실 수 있나요?"}, {"sp": "W", "en": "No, unfortunately. The parts have to be ordered. We could have it fixed by next week. As for the cost, let me check on everything . . . All right, the total will be $195.", "ko": "안타깝게도 안 돼요. 부품들이 주문되어야 하거든요. 저희는 다음 주까지 이걸 고칠 수 있을 거예요. 비용에 관해서는, 모두 확인해 볼게요… 좋아요, 총 195달러가 될 거예요."}, {"sp": "M", "en": "That's pretty expensive! Is there any way to lower the price?", "ko": "꽤 비싸네요! 가격을 낮출 수 있는 방법이 있나요?"}, {"sp": "W", "en": "I suppose the chain you have will be OK for another few months.", "ko": "손님이 갖고 계신 체인이 몇 달 동안은 괜찮을 거라고 생각되네요."}, {"sp": "M", "en": "Great. I'll get a new one later, then.", "ko": "좋아요. 그럼 나중에 새로 교체할게요."}], "gimg": "hk_t10_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "speakers": "M", "audio": "Test10_71-73.mp3", "qs": [{"n": 71, "q": "What was found in a store?", "opts": ["A garment", "A wallet", "An umbrella", "A wristwatch"], "ans": 0, "ko": "상점에서 무엇이 발견되었는가?"}, {"n": 72, "q": "What does the speaker mention about the information desk?", "opts": ["It is staffed by two people.", "It is marked with a sign.", "It is closing in five minutes.", "It is near the dairy section."], "ans": 3, "ko": "화자는 안내데스크에 관해 무엇을 언급하는가?"}, {"n": 73, "q": "What does the speaker say was recently introduced?", "opts": ["A delivery service", "A security measure", "A phone application", "A rewards program"], "ans": 0, "ko": "화자는 무엇이 최근에 시작되었다고 말하는가?"}], "script": [{"sp": "M", "en": "May I have your attention, shoppers? A sweater was found in our bakery section. It was left beside a sale sign and is gray with a black stripe across the back. If this item belongs to you, come to the information desk, which is situated next to our milk and cheese aisle . . . Also, I'd like to remind everyone that Smiling Grocery recently introduced a new service. Buy as many goods as you like, and we'll bring them to your residence within an hour, as long as you live here in Allensville.", "ko": "쇼핑객 여러분, 모두 주목해주시겠습니까? 저희 제과 매장에서 스웨터가 발견되었습니다. 그것은 할인 표지판 옆에 놓여 있었고 등 부분에 검은색 줄무늬가 있는 회색입니다. 만약 이 물건이 귀하의 것이라면, 우유와 치즈가 있는 통로 옆에 위치한 안내데스크로 와주시기 바랍니다… 또한, Smiling 식료품점이 최근에 새로운 서비스를 시작했다는 것을 모든 분께 다시 한번 말씀드리고 싶습니다. 원하시는 만큼 많은 물건을 구매하시면, 이곳 Allensville에 거주하시는 한 저희가 그것들을 한 시간 내에 귀하의 댁으로 가져다드리겠습니다."}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "speakers": "W", "audio": "Test10_74-76.mp3", "qs": [{"n": 74, "q": "What type of business does the listener most likely work for?", "opts": ["A restaurant chain", "A remodeling company", "A real-estate agency", "A market research firm"], "ans": 1, "ko": "청자는 어떤 종류의 업체에서 일하는 것 같은가?"}, {"n": 75, "q": "What does the speaker mean when she says, \"I think it would be better to do things differently\"?", "opts": ["She does not like a suggested item.", "A blueprint has not been accepted.", "A room should be emptied.", "She is willing to extend a deadline."], "ans": 0, "ko": "화자는 \"다르게 하는 게 더 좋을 것 같다고 생각해요\"라고 말할 때 무엇을 의도하는가?"}, {"n": 76, "q": "What does the speaker ask the listener to do?", "opts": ["Choose another color", "Send some options", "Invite some guests", "Save an e-mail address"], "ans": 1, "ko": "화자는 청자에게 무엇을 하라고 요청하는가?"}], "script": [{"sp": "W", "en": "Hi, Paul. This is Becky Landers. I looked over your proposal for redesigning my kitchen. I really like your choice of counter—it matches the tiles on the wall. But regarding, um, the sink you picked out . . . I think it would be better to do things differently. I live by myself, and I rarely have a large number of dishes to wash. So, it would be great if you could recommend a smaller model instead. Please try to e-mail me some options by 4 P.M.", "ko": "안녕하세요, Paul. 저는 Becky Landers입니다. 저의 부엌을 재설계하는 것에 대한 당신의 제안을 살펴보았습니다. 저는 당신이 선택한 조리대가 벽의 타일과 어울려서 매우 마음에 들어요. 하지만, 음, 당신이 고른 싱크대에 대해서는… 다르게 하는 게 더 좋을 것 같다고 생각해요. 저는 혼자 살고, 많은 접시를 닦을 일이 거의 없어요. 그러니, 당신이 더 작은 모델을 추천해 주신다면 좋을 것 같아요. 오후 4시까지 저에게 몇 가지 선택권들을 이메일로 보내주세요."}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "speakers": "M-Br", "audio": "Test10_77-79.mp3", "qs": [{"n": 77, "q": "Where most likely do the listeners work?", "opts": ["At a financial consulting agency", "At a corporate law firm", "At a public relations company", "At an educational institution"], "ans": 2, "ko": "청자들은 어디에서 일하는 것 같은가?"}, {"n": 78, "q": "According to the speaker, what will happen tomorrow?", "opts": ["Some staff will be transferred.", "A break room will be closed off.", "A training session will be held.", "Some refreshments will be available."], "ans": 3, "ko": "화자에 따르면, 내일 무슨 일이 일어날 것인가?"}, {"n": 79, "q": "What does the speaker encourage the listeners to do?", "opts": ["Work overtime hours", "Apply for a job", "Attend a corporate picnic", "Speak with a manager"], "ans": 3, "ko": "화자는 청자들에게 무엇을 하라고 권하는가?"}], "script": [{"sp": "M", "en": "I want you all to meet Ahmed Pearce, our new managing director. Mr. Pearce has overseen public relations firms like ours for over a decade now, so he has plenty of experience. Moreover, he's a very friendly, approachable person. I'm sure you'll all appreciate working under him. I've arranged for some bagels, muffins, and coffee to be delivered to our break room tomorrow morning for you to enjoy while introducing yourself to Mr. Pearce.", "ko": "저는 여러분께서 우리의 새로운 상무 이사인 Ahmed Pearce를 만나시길 바랍니다. Mr. Pearce는 우리와 같은 홍보 회사들을 지금까지 10년이 넘게 관리해왔기에, 많은 경험을 가지고 있습니다. 게다가, 그는 매우 친절하고 사귀기 쉬운 사람입니다. 여러분 모두 그의 밑에서 일하는 것을 환영하실 거라고 확신합니다. 내일 아침 Mr. Pearce에게 여러분 스스로를 소개하실 동안 즐기실 수 있는 베이글, 머핀, 그리고 커피가 휴게실로 배달되도록 준비했습니다."}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "speakers": "M-Cn", "audio": "Test10_80-82.mp3", "qs": [{"n": 80, "q": "According to the speaker, what has a team been working on?", "opts": ["A company symbol", "Clothing designs", "A business deal", "Office renovations"], "ans": 0, "ko": "화자에 따르면, 팀은 무엇을 작업하고 있는가?"}, {"n": 81, "q": "What does the speaker say clients will be given?", "opts": ["Business brochures", "Branded gifts", "Updated contracts", "Price estimates"], "ans": 1, "ko": "화자는 고객들이 무엇을 받을 것이라고 말하는가?"}, {"n": 82, "q": "Why does the speaker say, \"The more, the better\"?", "opts": ["To welcome personnel", "To encourage suggestions", "To accept an offer", "To praise an achievement"], "ans": 1, "ko": "화자는 왜 \"많으면 많을수록 좋습니다\"라고 말하는가?"}], "script": [{"sp": "M", "en": "I'm sure you're all as eager as I am to see the new company logo that our graphic design team has been working on. It will be unveiled next week at the trade show, after which we'll give each of our clients small presents with the logo on them. For instance, we're planning to hand out pens as well as key chains. If you have ideas for other items we could distribute, I'm open to them. The more, the better.", "ko": "저는 우리 그래픽 디자인팀이 작업해온 새로운 회사 로고를 여러분 모두가 저만큼 몹시 보고 싶어 하실 거라고 생각합니다. 그것은 다음 주 무역 박람회에서 발표될 것이고, 그 이후에 각 고객들에게 로고가 있는 작은 선물을 드릴 것입니다. 예를 들어, 열쇠고리뿐만 아니라 펜도 나눠줄 계획입니다. 만약 여러분이 우리가 배부할 수 있는 다른 물품들에 대한 의견이 있다면, 그것을 고려할 것입니다. 많으면 많을수록 좋습니다."}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "speakers": "W-Br", "audio": "Test10_83-85.mp3", "qs": [{"n": 83, "q": "Who is the speaker going to interview?", "opts": ["A zoo official", "A filmmaker", "A travel blogger", "A scientist"], "ans": 1, "ko": "화자는 누구를 인터뷰할 것인가?"}, {"n": 84, "q": "What does the speaker imply when she says, \"I've got no reason to doubt them\"?", "opts": ["A project goal will be met.", "Some praise is justified.", "A campaign will be successful.", "Some concerns are valid."], "ans": 1, "ko": "화자는 \"저는 그들을 의심할 여지가 없습니다\"라고 말할 때 무엇을 의도하는가?"}, {"n": 85, "q": "What will listeners most likely hear next?", "opts": ["Details about an event", "Advertisements from sponsors", "Comments about a production", "Information from a reporter"], "ans": 3, "ko": "청자들은 다음에 무엇을 들을 것 같은가?"}], "script": [{"sp": "W", "en": "This is Haley Woodson, and you're listening to Movies Today on WMMZ 99.5 Radio. This morning, I'll be interviewing director Marcy Sawyer about her latest documentary film, Wild Serengeti, which was released just two weeks ago. It contains never-before-seen footage of endangered animals living in western Africa and advocates for the protection of wildlife in that region. In just a moment, Ms. Sawyer will tell us all about her joys and struggles living and working abroad for nearly four months. Critics have loved the film, and I've got no reason to doubt them. But first, let's take a few minutes to listen to the morning news highlights from our reporter Shirley Quinn.", "ko": "저는 Haley Woodson이고, 여러분께서는 WMMZ 99.5 라디오의 Movies Today를 듣고 계십니다. 오늘 아침, 저는 Marcy Sawyer 감독과 그녀의 최신 다큐멘터리 영화인 Wild Serengeti에 대해 인터뷰할 것인데, 그 영화는 2주 전에 막 개봉했습니다. 영화는 서아프리카에 살고 있는 멸종 위기에 처한 동물들에 대해 지금까지 보지 못했던 장면들을 담고 있고, 그 지역의 야생동물의 보호를 지지하고 있습니다. 바로 잠시 후에, Ms. Sawyer는 거의 4개월 간 해외에서 살며 일하는 것의 기쁨과 고된 노력에 대해 우리 모두에게 말해줄 것입니다. 비평가들은 그 영화를 매우 좋아했고, 저는 그들을 의심할 여지가 없습니다. 그러나 먼저, Shirley Quinn 기자의 아침 주요 뉴스를 잠시 들으시겠습니다."}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "speakers": "M-Cn", "audio": "Test10_86-88.mp3", "qs": [{"n": 86, "q": "What does the speaker inform the listener about?", "opts": ["A loyalty program", "A service price", "A new stylist", "A schedule change"], "ans": 3, "ko": "화자는 청자에게 무엇에 대해 알리는가?"}, {"n": 87, "q": "What is offered to the listener?", "opts": ["A membership card", "A follow-up consultation", "A hair-care product", "A gift certificate"], "ans": 2, "ko": "청자에게 무엇이 제공되는가?"}, {"n": 88, "q": "What does the speaker say is inaccessible?", "opts": ["An elevator", "A parking lot", "A staircase", "A waiting area"], "ans": 0, "ko": "화자는 무엇을 이용할 수 없다고 말하는가?"}], "script": [{"sp": "M", "en": "Hi, Clara. This is Shawn from BeBelle Hair Salon. I'm calling you regarding your cutting and styling appointment today with Steve. Unfortunately, he is running late today, and we're wondering whether you're open to coming an hour later than originally planned. I know this is an inconvenience, and we're very sorry. If you agree, we'd be happy to give you a complimentary bottle of shampoo. Oh . . . one more thing. Our building's elevator is currently out of service, so you'll have to take the stairs to the second floor whenever you arrive. I look forward to hearing from you.", "ko": "안녕하세요, Clara. 저는 BeBelle Hair Salon의 Shawn입니다. 오늘 Steve와의 커팅 및 스타일링 약속과 관련하여 전화드립니다. 유감스럽게도, 그가 오늘 늦게 되어 손님께서 원래 예정보다 한 시간 늦게 오시는 것이 괜찮으신지 궁금합니다. 이것이 불편한 일이라는 것을 알고 있고, 저희는 매우 죄송하게 생각합니다. 만약 손님께서 승낙하신다면, 저희가 무료 샴푸 한 병을 드리고자 합니다. 아... 한 가지 더 있습니다. 저희 건물의 엘리베이터가 현재 고장이 나서, 도착하시면 2층까지 계단을 사용하셔야 할 것입니다. 연락 기다리겠습니다."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "speakers": "W-Am", "audio": "Test10_89-91.mp3", "qs": [{"n": 89, "q": "Who most likely are the listeners?", "opts": ["Electronics salespeople", "Computer programmers", "Product designers", "Media representatives"], "ans": 0, "ko": "청자들은 누구인 것 같은가?"}, {"n": 90, "q": "What does the speaker suggest?", "opts": ["Posting about a product online", "Setting up some displays", "Correcting some malfunctions", "Becoming familiar with a device"], "ans": 3, "ko": "화자는 무엇을 제안하는가?"}, {"n": 91, "q": "What feature distinguishes the Koring Pro?", "opts": ["It comes in multiple colors.", "It does not need a cord to function.", "It contains built-in speakers.", "It is compatible with previous models."], "ans": 1, "ko": "어떤 특징이 Koring Pro를 구별 짓는가?"}], "script": [{"sp": "W", "en": "We will begin selling a new keyboard on Tuesday. As you will need to introduce this product to our customers, you should get to know its features as quickly as possible. It's called the Koring Pro, and it's made by Leino. What makes this item stand out is that it has no cord. It connects wirelessly to computers, tablets, and phones. And it's quite affordable. The price here at Gadget Warehouse will be $21. In time, I think it'll become one of our best sellers.", "ko": "우리는 화요일에 새 키보드를 판매하기 시작할 것입니다. 여러분께서 이 제품을 우리 고객들에게 소개하셔야 하므로, 가능한 한 빨리 그것의 특징들을 익히셔야 합니다. 그것은 Koring Pro라고 하며, Leino사에 의해 만들어졌습니다. 이 제품을 돋보이게 만드는 것은 코드가 없다는 것입니다. 그것은 컴퓨터, 태블릿, 그리고 휴대 전화에 무선으로 연결됩니다. 그리고 그것은 가격이 꽤 적당합니다. 이곳 Gadget Warehouse에서의 가격은 21달러일 것입니다. 조만간, 그것은 우리의 가장 잘 팔리는 상품들 중 하나가 될 것이라고 생각합니다."}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "speakers": "W-Am", "audio": "Test10_92-94.mp3", "qs": [{"n": 92, "q": "What is the report mainly about?", "opts": ["A business opening", "A product release", "A health study", "A company acquisition"], "ans": 1, "ko": "보도는 주로 무엇에 관한 것인가?"}, {"n": 93, "q": "According to the speaker, what took place in the spring?", "opts": ["A product trial", "An awareness campaign", "A seasonal promotion", "A national recall"], "ans": 0, "ko": "화자에 따르면, 봄에 무슨 일이 일어났는가?"}, {"n": 94, "q": "Why was the preorder service halted?", "opts": ["It proved to be too popular.", "It violated state regulations.", "It was not approved by a CEO.", "It cost a lot of money."], "ans": 0, "ko": "예약 주문 서비스는 왜 중단되었는가?"}], "script": [{"sp": "W", "en": "This is Catherine Long with BBS News. Our top business story today is about the launch of JarinSport's highly anticipated running shoe line. The shoes have been designed to include computer chips that record the wearer's distance traveled and calories burned and send the information to a smartphone application for review. Consumers who participated in the product testing carried out this spring showed promising levels of satisfaction. The line of shoes hits stores early this May. Unfortunately, JarinSport has stopped accepting advance orders due to an unexpectedly high volume of requests placed through its Web site.", "ko": "저는 BBS News의 Catherine Long입니다. 오늘 화제의 사업 소식은 JarinSport사의 매우 기대되는 운동화 제품 출시에 대한 것입니다. 그 운동화는 착용한 사람의 이동 거리와 소비된 칼로리를 기록하고, 검토를 위해 그 정보를 스마트폰의 애플리케이션으로 전송하는 컴퓨터 칩을 포함하도록 만들어졌습니다. 올 봄에 실시된 제품 시험에 참여했던 소비자들은 전망이 좋은 수준의 만족도를 보였습니다. 이 운동화 제품은 5월 초에 매장에 출시됩니다. 안타깝게도, JarinSport사는 웹사이트를 통해 이루어진 예상 외로 많은 양의 요청으로 인해 예약 주문을 받는 것을 중단했습니다."}]}, {"start": 95, "part": 4, "intro": "", "graphic": true, "speakers": "M", "audio": "Test10_95-97.mp3", "qs": [{"n": 95, "q": "What does the speaker mention about the convention?", "opts": ["It is a yearly event.", "It is in a new location.", "It attracts international attendees.", "It focuses mostly on small firms."], "ans": 0, "ko": "화자는 컨벤션에 관해 무엇을 언급하는가?"}, {"n": 96, "q": "According to the speaker, why should listeners register early?", "opts": ["To pay a reduced fee", "To have more session options", "To secure an inexpensive seat", "To avoid waiting in line"], "ans": 1, "ko": "화자에 따르면, 청자들은 왜 일찍 등록해야 하는가?"}, {"n": 97, "q": "Look at the graphic. What information did the speaker incorrectly state?", "opts": ["The presenter's name", "The session's title", "The start time", "The venue name"], "ans": 3, "ko": "시각 자료를 보시오. 화자는 어떤 정보를 부정확하게 언급했는가?"}], "script": [{"sp": "M", "en": "Good morning, and welcome to the seventh annual Baltimore Marketing Convention. We ask you all to register for any seminars that you want to attend at our enrollment desk. And remember, some sessions are expected to fill up fast, so you'll have a greater variety of choices if you register sooner rather than later. As for Gilbert Park's seminar on global advertising, it will take place at 10:45 this morning in Rose Hall. However, since there's only space for . . . ah . . . 50 attendees in that room, the talk will be recorded and streamed live on a television in Conference Room C. Those who don't secure seats can watch the event there.", "ko": "안녕하세요, 제7회 연례 볼티모어 마케팅 컨벤션에 오신 것을 환영합니다. 여러분께서 참여하시길 원하는 어떤 세미나든 저희 등록 데스크에서 등록해 주시길 요청 드립니다. 그리고 기억해 주십시오, 일부 강의들은 빠르게 찰 것으로 예상되므로, 차라리 일찍 등록한다면 더 다양한 선택권을 갖게 되실 겁니다. 국제 광고에 대한 Gilbert Park의 세미나에 관해서, 그것은 오늘 오전 10시 45분에 Rose홀에서 열릴 것입니다. 그러나 그 방에는 단지… 아… 50명의 참석자들을 위한 자리만 있기 때문에, 연설은 녹화되어 C회의실에 있는 텔레비전을 통해 실시간으로 재생될 것입니다. 좌석을 확보하지 못한 분들께서는 그곳에서 행사를 시청하실 수 있습니다."}], "gimg": "hk_t10_g95.jpg"}, {"start": 98, "part": 4, "intro": "", "graphic": true, "speakers": "M", "audio": "Test10_98-100.mp3", "qs": [{"n": 98, "q": "According to the speaker, where was a debit card used yesterday?", "opts": ["At an international airport", "At an apparel retailer", "At a luxury resort", "At a fast food restaurant"], "ans": 1, "ko": "화자에 따르면, 어제 현금 카드가 어디에서 사용되었는가?"}, {"n": 99, "q": "Why must the listener place a call?", "opts": ["To track some parcels", "To take advantage of a deal", "To confirm a purchase", "To make travel arrangements"], "ans": 2, "ko": "청자는 왜 전화를 해야 하는가?"}, {"n": 100, "q": "Look at the graphic. Which office should the listener contact?", "opts": ["Denver", "Seattle", "Tacoma", "Phoenix"], "ans": 3, "ko": "시각 자료를 보시오. 청자는 어느 지점에 연락해야 하는가?"}], "script": [{"sp": "M", "en": "Good afternoon. This is Jonathan Rivers calling from Partners Bank for Helen Wong. Ms. Wong, I'd like to let you know that your debit card may have been used by an unauthorized person. A purchase was made with your card yesterday at a luxury clothing store in Barcelona. However, our records indicate that you live in Seattle. In order to discuss the matter further, please call 555-3422. This number will connect you with the customer service center at our main branch, and a representative will assist you. Thank you.", "ko": "안녕하세요. 저는 Helen Wong님께 전화드리는 Partners 은행의 Jonathan Rivers입니다. Ms. Wong, 저는 귀하의 현금 카드가 권한이 없는 사용자에 의해 쓰였을 수도 있다는 것을 알려드리고 싶습니다. 귀하의 카드로 어제 바르셀로나에 있는 고급 의류 상점에서 구매가 이루어졌습니다. 그러나, 저희의 기록에는 귀하가 시애틀에 살고 계시다고 나옵니다. 이 문제를 더 논의하시려면, 555-3422로 전화해 주시기 바랍니다. 이 번호는 저희 본사에 있는 고객 서비스 센터로 연결될 것이고, 담당자가 도와드릴 것입니다. 감사합니다."}], "gimg": "hk_t10_g98.jpg"}]};
